/* Neon Runner - Cyberpunk Theme CSS */
:root {
  --neon-blue: #00FFFF;
  --neon-pink: #FF1493;
  --neon-purple: #8A2BE2;
  --neon-green: #00FF00;
  --neon-orange: #FFA500;
  --bg-dark: #000011;
  --bg-darker: #000000;
  --text-primary: #FFFFFF;
  --text-secondary: #CCCCCC;
  --border-glow: rgba(0, 255, 255, 0.5);
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Orbitron', monospace;
  background: linear-gradient(135deg, var(--bg-darker) 0%, var(--bg-dark) 100%);
  color: var(--text-primary);
  overflow: hidden;
  min-height: 100vh;
}

#game-container {
  display: flex;
  flex-direction: column;
  height: 100vh;
  background: radial-gradient(ellipse at center, rgba(0, 255, 255, 0.1) 0%, transparent 70%);
}

/* Header Styles */
#game-header {
  background: linear-gradient(90deg, rgba(0, 0, 0, 0.9) 0%, rgba(0, 17, 17, 0.9) 100%);
  border-bottom: 2px solid var(--border-glow);
  padding: 1rem;
  box-shadow: 0 0 20px rgba(0, 255, 255, 0.3);
}

.header-content {
  display: flex;
  justify-content: space-between;
  align-items: center;
  max-width: 1200px;
  margin: 0 auto;
}

.game-title {
  display: flex;
  gap: 1rem;
  font-size: 2rem;
  font-weight: 900;
  letter-spacing: 0.2em;
}

.neon-text {
  color: var(--neon-blue);
  text-shadow: 
    0 0 5px currentColor,
    0 0 10px currentColor,
    0 0 20px currentColor,
    0 0 40px currentColor;
  animation: neon-flicker 2s infinite alternate;
}

.neon-text-secondary {
  color: var(--neon-pink);
  text-shadow: 
    0 0 5px currentColor,
    0 0 10px currentColor,
    0 0 20px currentColor,
    0 0 40px currentColor;
  animation: neon-flicker 2s infinite alternate-reverse;
}

@keyframes neon-flicker {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.8; }
}

.game-stats {
  display: flex;
  gap: 2rem;
}

.stat-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.25rem;
}

.stat-label {
  font-size: 0.7rem;
  color: var(--text-secondary);
  letter-spacing: 0.1em;
}

.stat-value {
  font-size: 1.2rem;
  font-weight: 700;
}

/* Main Game Area */
#game-main {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
  position: relative;
  background: 
    radial-gradient(circle at 20% 80%, rgba(138, 43, 226, 0.1) 0%, transparent 50%),
    radial-gradient(circle at 80% 20%, rgba(255, 20, 147, 0.1) 0%, transparent 50%);
}

#game-canvas {
  border: 2px solid var(--border-glow);
  border-radius: 8px;
  box-shadow: 
    0 0 20px rgba(0, 255, 255, 0.3),
    inset 0 0 20px rgba(0, 255, 255, 0.1);
  background: rgba(0, 0, 0, 0.8);
}

/* Overlay Screens */
#game-overlay {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  display: flex;
  justify-content: center;
  align-items: center;
  pointer-events: none;
}

.overlay-screen {
  background: rgba(0, 0, 0, 0.9);
  border: 2px solid var(--border-glow);
  border-radius: 16px;
  padding: 3rem;
  text-align: center;
  box-shadow: 
    0 0 30px rgba(0, 255, 255, 0.4),
    inset 0 0 30px rgba(0, 255, 255, 0.1);
  pointer-events: auto;
  animation: fade-in 0.5s ease-out;
}

.overlay-screen.hidden {
  display: none;
}

@keyframes fade-in {
  from { opacity: 0; transform: scale(0.9); }
  to { opacity: 1; transform: scale(1); }
}

/* Loading Screen */
.loading-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1.5rem;
}

.loading-title {
  font-size: 1.5rem;
  font-weight: 700;
}

.loading-bar {
  width: 300px;
  height: 20px;
  background: rgba(0, 255, 255, 0.1);
  border: 1px solid var(--neon-blue);
  border-radius: 10px;
  overflow: hidden;
  position: relative;
}

.loading-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--neon-blue), var(--neon-purple));
  border-radius: 10px;
  transition: width 0.3s ease;
  animation: loading-pulse 1.5s infinite;
}

@keyframes loading-pulse {
  0%, 100% { box-shadow: 0 0 10px var(--neon-blue); }
  50% { box-shadow: 0 0 20px var(--neon-blue), 0 0 30px var(--neon-purple); }
}

.loading-status {
  color: var(--text-secondary);
  font-size: 0.9rem;
}

/* Start Screen */
.start-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2rem;
}

.start-title {
  font-size: 2rem;
  margin-bottom: 1rem;
}

.controls-info {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 1rem;
  margin-bottom: 1rem;
}

.control-item {
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 0.5rem;
  border: 1px solid rgba(0, 255, 255, 0.3);
  border-radius: 8px;
  background: rgba(0, 255, 255, 0.05);
}

.key-icon {
  padding: 0.5rem 1rem;
  background: linear-gradient(135deg, var(--neon-blue), var(--neon-purple));
  color: var(--bg-darker);
  font-weight: 700;
  border-radius: 6px;
  box-shadow: 0 0 10px rgba(0, 255, 255, 0.5);
  min-width: 60px;
  text-align: center;
}

.key-label {
  font-size: 0.9rem;
  color: var(--text-secondary);
}

/* Buttons */
.neon-button {
  padding: 1rem 2rem;
  background: linear-gradient(135deg, transparent, rgba(0, 255, 255, 0.1));
  border: 2px solid var(--neon-blue);
  border-radius: 8px;
  color: var(--neon-blue);
  font-family: 'Orbitron', monospace;
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.3s ease;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  position: relative;
  overflow: hidden;
}

.neon-button:hover {
  background: linear-gradient(135deg, rgba(0, 255, 255, 0.1), rgba(0, 255, 255, 0.2));
  box-shadow: 
    0 0 20px rgba(0, 255, 255, 0.5),
    inset 0 0 20px rgba(0, 255, 255, 0.1);
  transform: translateY(-2px);
}

.neon-button:active {
  transform: translateY(0);
}

.neon-button-secondary {
  padding: 0.75rem 1.5rem;
  background: transparent;
  border: 1px solid var(--neon-pink);
  border-radius: 6px;
  color: var(--neon-pink);
  font-family: 'Orbitron', monospace;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  text-transform: uppercase;
}

.neon-button-secondary:hover {
  background: rgba(255, 20, 147, 0.1);
  box-shadow: 0 0 15px rgba(255, 20, 147, 0.4);
}

/* Game Over Screen */
.game-over-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2rem;
}

.game-over-title {
  font-size: 2.5rem;
  color: var(--neon-pink);
  margin-bottom: 1rem;
}

.final-stats {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.final-stat {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 2rem;
  padding: 0.5rem;
  border-bottom: 1px solid rgba(0, 255, 255, 0.3);
}

.game-over-actions {
  display: flex;
  gap: 1rem;
}

/* Footer */
#game-footer {
  background: linear-gradient(90deg, rgba(0, 0, 0, 0.9) 0%, rgba(0, 17, 17, 0.9) 100%);
  border-top: 1px solid var(--border-glow);
  padding: 0.5rem 1rem;
}

.footer-content {
  display: flex;
  justify-content: space-between;
  align-items: center;
  max-width: 1200px;
  margin: 0 auto;
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.game-info, .performance-stats {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.separator {
  color: var(--neon-blue);
}

.perf-stat {
  color: var(--neon-green);
}

/* Utility Classes */
.hidden {
  display: none !important;
}

/* Particle Effects */
.particle {
  position: absolute;
  width: 2px;
  height: 2px;
  background: var(--neon-blue);
  border-radius: 50%;
  pointer-events: none;
  animation: particle-float 2s linear infinite;
}

@keyframes particle-float {
  0% {
    transform: translateY(0) scale(1);
    opacity: 1;
  }
  100% {
    transform: translateY(-100px) scale(0);
    opacity: 0;
  }
}

/* Responsive Design */
@media (max-width: 1000px) {
  #game-canvas {
    width: 90vw;
    height: auto;
  }

  .game-title {
    font-size: 1.5rem;
  }

  .overlay-screen {
    padding: 2rem;
    margin: 1rem;
  }

  .controls-info {
    grid-template-columns: 1fr;
  }
}

