// Game Constants for Neon Runner
export const GAME_CONSTANTS = {
  // Canvas settings
  CANVAS_WIDTH: 800,
  CANVAS_HEIGHT: 600,

  // Player settings
  PLAYER_SIZE: 20,
  PLAYER_SPEED: 300, // pixels per second
  PLAYER_COLOR: '#00FFFF',
  PLAYER_GLOW: '#00FFFF',

  // Obstacle settings
  OBSTACLE_MIN_SIZE: 30,
  OBSTACLE_MAX_SIZE: 80,
  OBSTACLE_SPEED: 200,
  OBSTACLE_SPAWN_INTERVAL: 2000, // milliseconds
  OBSTACLE_COLOR: '#FF1493',

  // Power-up settings
  POWERUP_SIZE: 25,
  POWERUP_SPEED: 150,
  POWERUP_SPAWN_INTERVAL: 5000,
  POWERUP_COLOR: '#00FF00',
  POWERUP_DURATION: 3000, // effect duration in ms

  // Scoring
  SCORE_PER_SECOND: 10,
  SCORE_POWERUP: 100,
  SCORE_OBSTACLE_DODGE: 50,

  // Physics
  FRICTION: 0.9,
  MAX_VELOCITY: 400,

  // Particles
  MAX_PARTICLES: 100,
  PARTICLE_LIFETIME: 1000,

  // Game states
  STATES: {
    LOADING: 'loading',
    MENU: 'menu',
    PLAYING: 'playing',
    PAUSED: 'paused',
    GAME_OVER: 'gameOver'
  }
};

export const INPUT_KEYS = {
  UP: 'ArrowUp',
  DOWN: 'ArrowDown',
  LEFT: 'ArrowLeft',
  RIGHT: 'ArrowRight',
  SPACE: 'Space',
  ESCAPE: 'Escape'
};

// Game Constants for Neon Runner
export const GAME_CONSTANTS = {
  // Canvas settings
  CANVAS_WIDTH: 800,
  CANVAS_HEIGHT: 600,

  // Player settings
  PLAYER_SIZE: 20,
  PLAYER_SPEED: 300, // pixels per second
  PLAYER_COLOR: '#00FFFF',
  PLAYER_GLOW: '#00FFFF',

  // Obstacle settings
  OBSTACLE_MIN_SIZE: 30,
  OBSTACLE_MAX_SIZE: 80,
  OBSTACLE_SPEED: 200,
  OBSTACLE_SPAWN_INTERVAL: 2000, // milliseconds
  OBSTACLE_COLOR: '#FF1493',

  // Power-up settings
  POWERUP_SIZE: 25,
  POWERUP_SPEED: 150,
  POWERUP_SPAWN_INTERVAL: 5000,
  POWERUP_COLOR: '#00FF00',
  POWERUP_DURATION: 3000, // effect duration in ms

  // Scoring
  SCORE_PER_SECOND: 10,
  SCORE_POWERUP: 100,
  SCORE_OBSTACLE_DODGE: 50,

  // Physics
  FRICTION: 0.9,
  MAX_VELOCITY: 400,

  // Particles
  MAX_PARTICLES: 100,
  PARTICLE_LIFETIME: 1000,

  // Game states
  STATES: {
    LOADING: 'loading',
    MENU: 'menu',
    PLAYING: 'playing',
    PAUSED: 'paused',
    GAME_OVER: 'gameOver'
  }
};

export const INPUT_KEYS = {
  UP: 'ArrowUp',
  DOWN: 'ArrowDown',
  LEFT: 'ArrowLeft',
  RIGHT: 'ArrowRight',
  SPACE: 'Space',
  ESCAPE: 'Escape'
};

import { INPUT_KEYS } from '../utils/Constants.js';

/**
 * Input Manager for handling keyboard input
 * Provides smooth, responsive arrow key controls
 */
export class InputManager {
  constructor() {
    this.keys = {};
    this.keyPressed = {};
    this.keyReleased = {};
    this.setupEventListeners();
  }

  setupEventListeners() {
    // Handle keydown events
    document.addEventListener('keydown', (e) => {
      if (Object.values(INPUT_KEYS).includes(e.code)) {
        e.preventDefault();

        // Track key press (only once per press)
        if (!this.keys[e.code]) {
          this.keyPressed[e.code] = true;
        }

        this.keys[e.code] = true;
      }
    });

    // Handle keyup events
    document.addEventListener('keyup', (e) => {
      if (Object.values(INPUT_KEYS).includes(e.code)) {
        e.preventDefault();
        this.keys[e.code] = false;
        this.keyReleased[e.code] = true;
      }
    });

    // Handle focus events to prevent stuck keys
    window.addEventListener('blur', () => {
      this.resetAll();
    });
  }

  /**
   * Check if a key is currently being held down
   */
  isKeyDown(keyCode) {
    return this.keys[keyCode] || false;
  }

  /**
   * Check if a key was just pressed this frame
   */
  wasKeyPressed(keyCode) {
    return this.keyPressed[keyCode] || false;
  }

  /**
   * Check if a key was just released this frame
   */
  wasKeyReleased(keyCode) {
    return this.keyReleased[keyCode] || false;
  }

  /**
   * Get movement vector based on arrow key input
   */
  getMovementVector() {
    const movement = { x: 0, y: 0 };

    if (this.isKeyDown(INPUT_KEYS.LEFT)) {
      movement.x -= 1;
    }
    if (this.isKeyDown(INPUT_KEYS.RIGHT)) {
      movement.x += 1;
    }
    if (this.isKeyDown(INPUT_KEYS.UP)) {
      movement.y -= 1;
    }
    if (this.isKeyDown(INPUT_KEYS.DOWN)) {
      movement.y += 1;
    }

    // Normalize diagonal movement
    if (movement.x !== 0 && movement.y !== 0) {
      const length = Math.sqrt(movement.x * movement.x + movement.y * movement.y);
      movement.x /= length;
      movement.y /= length;
    }

    return movement;
  }

  /**
   * Reset all input states (called at end of frame)
   */
  update() {
    this.keyPressed = {};
    this.keyReleased = {};
  }

  /**
   * Reset all keys (used when losing focus)
   */
  resetAll() {
    this.keys = {};
    this.keyPressed = {};
    this.keyReleased = {};
  }
}

/**
 * Collision Detection System for Neon Runner
 * Handles all collision detection with optimized algorithms
 */
export class CollisionDetector {

  /**
   * Check collision between two rectangular objects
   */
  static checkRectCollision(rect1, rect2) {
    return rect1.x < rect2.x + rect2.width &&
           rect1.x + rect1.width > rect2.x &&
           rect1.y < rect2.y + rect2.height &&
           rect1.y + rect1.height > rect2.y;
  }

  /**
   * Check collision between two circular objects
   */
  static checkCircleCollision(circle1, circle2) {
    const dx = circle1.x - circle2.x;
    const dy = circle1.y - circle2.y;
    const distance = Math.sqrt(dx * dx + dy * dy);
    return distance < (circle1.radius + circle2.radius);
  }

  /**
   * Check collision between circle and rectangle
   */
  static checkCircleRectCollision(circle, rect) {
    const closestX = Math.max(rect.x, Math.min(circle.x, rect.x + rect.width));
    const closestY = Math.max(rect.y, Math.min(circle.y, rect.y + rect.height));

    const dx = circle.x - closestX;
    const dy = circle.y - closestY;

    return (dx * dx + dy * dy) < (circle.radius * circle.radius);
  }

  /**
   * Check if object is within canvas boundaries
   */
  static checkBoundaries(object, canvasWidth, canvasHeight) {
    const bounds = {
      left: object.x < 0,
      right: object.x + object.width > canvasWidth,
      top: object.y < 0,
      bottom: object.y + object.height > canvasHeight
    };

    return {
      isOutOfBounds: bounds.left || bounds.right || bounds.top || bounds.bottom,
      ...bounds
    };
  }

  /**
   * Get collision info with detailed data
   */
  static getCollisionInfo(obj1, obj2) {
    if (!this.checkRectCollision(obj1, obj2)) {
      return null;
    }

    // Calculate overlap amounts
    const overlapX = Math.min(obj1.x + obj1.width - obj2.x, obj2.x + obj2.width - obj1.x);
    const overlapY = Math.min(obj1.y + obj1.height - obj2.y, obj2.y + obj2.height - obj1.y);

    // Determine collision direction
    let direction = 'none';
    if (overlapX < overlapY) {
      direction = obj1.x < obj2.x ? 'right' : 'left';
    } else {
      direction = obj1.y < obj2.y ? 'down' : 'up';
    }

    return {
      hasCollision: true,
      overlapX,
      overlapY,
      direction
    };
  }

  /**
   * Spatial partitioning for performance optimization
   * Divide the game world into grid cells for efficient collision detection
   */
  static createSpatialGrid(objects, cellSize = 100) {
    const grid = new Map();

    objects.forEach(obj => {
      const cellX = Math.floor(obj.x / cellSize);
      const cellY = Math.floor(obj.y / cellSize);
      const key = `${cellX},${cellY}`;

      if (!grid.has(key)) {
        grid.set(key, []);
      }
      grid.get(key).push(obj);
    });

    return grid;
  }

  /**
   * Get potential collision candidates using spatial partitioning
   */
  static getPotentialCollisions(object, grid, cellSize = 100) {
    const candidates = [];
    const cellX = Math.floor(object.x / cellSize);
    const cellY = Math.floor(object.y / cellSize);

    // Check surrounding cells
    for (let x = cellX - 1; x <= cellX + 1; x++) {
      for (let y = cellY - 1; y <= cellY + 1; y++) {
        const key = `${x},${y}`;
        if (grid.has(key)) {
          candidates.push(...grid.get(key));
        }
      }
    }

    return candidates;
  }
}

import { GAME_CONSTANTS } from '../utils/Constants.js';

/**
 * Rendering System for Neon Runner
 * Handles all canvas drawing with neon visual effects
 */
export class Renderer {
  constructor(canvas, ctx) {
    this.canvas = canvas;
    this.ctx = ctx;
    this.setupCanvas();
  }

  setupCanvas() {
    // Set canvas size
    this.canvas.width = GAME_CONSTANTS.CANVAS_WIDTH;
    this.canvas.height = GAME_CONSTANTS.CANVAS_HEIGHT;

    // Enable smooth rendering
    this.ctx.imageSmoothingEnabled = true;
    this.ctx.imageSmoothingQuality = 'high';
  }

  /**
   * Clear the entire canvas with dark background
   */
  clear() {
    // Create gradient background
    const gradient = this.ctx.createLinearGradient(0, 0, 0, this.canvas.height);
    gradient.addColorStop(0, '#000011');
    gradient.addColorStop(1, '#000000');

    this.ctx.fillStyle = gradient;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    // Add subtle grid pattern
    this.drawGrid();
  }

  /**
   * Draw cyberpunk grid background
   */
  drawGrid() {
    this.ctx.strokeStyle = 'rgba(0, 255, 255, 0.1)';
    this.ctx.lineWidth = 1;
    this.ctx.setLineDash([5, 5]);

    const gridSize = 50;

    // Vertical lines
    for (let x = 0; x <= this.canvas.width; x += gridSize) {
      this.ctx.beginPath();
      this.ctx.moveTo(x, 0);
      this.ctx.lineTo(x, this.canvas.height);
      this.ctx.stroke();
    }

    // Horizontal lines
    for (let y = 0; y <= this.canvas.height; y += gridSize) {
      this.ctx.beginPath();
      this.ctx.moveTo(0, y);
      this.ctx.lineTo(this.canvas.width, y);
      this.ctx.stroke();
    }

    this.ctx.setLineDash([]);
  }

  /**
   * Draw neon glow effect
   */
  drawNeonGlow(x, y, width, height, color, intensity = 1) {
    const glowSize = 20 * intensity;

    // Create radial gradient for glow
    const centerX = x + width / 2;
    const centerY = y + height / 2;
    const radius = Math.max(width, height) / 2 + glowSize;

    const gradient = this.ctx.createRadialGradient(
      centerX, centerY, 0,
      centerX, centerY, radius
    );

    gradient.addColorStop(0, color);
    gradient.addColorStop(0.3, color + '80');
    gradient.addColorStop(0.7, color + '20');
    gradient.addColorStop(1, 'transparent');

    this.ctx.fillStyle = gradient;
    this.ctx.fillRect(x - glowSize, y - glowSize, width + glowSize * 2, height + glowSize * 2);
  }

  /**
   * Draw rectangle with neon effect
   */
  drawNeonRect(x, y, width, height, color, glowIntensity = 1) {
    // Draw glow first
    this.drawNeonGlow(x, y, width, height, color, glowIntensity);

    // Draw main shape
    this.ctx.fillStyle = color;
    this.ctx.shadowColor = color;
    this.ctx.shadowBlur = 15 * glowIntensity;
    this.ctx.fillRect(x, y, width, height);

    // Draw bright border
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = 2;
    this.ctx.shadowBlur = 5;
    this.ctx.strokeRect(x, y, width, height);

    // Reset shadow
    this.ctx.shadowBlur = 0;
  }

  /**
   * Draw circle with neon effect
   */
  drawNeonCircle(x, y, radius, color, glowIntensity = 1) {
    // Draw glow
    const glowRadius = radius + 10 * glowIntensity;
    const gradient = this.ctx.createRadialGradient(x, y, 0, x, y, glowRadius);
    gradient.addColorStop(0, color);
    gradient.addColorStop(0.5, color + '60');
    gradient.addColorStop(1, 'transparent');

    this.ctx.fillStyle = gradient;
    this.ctx.beginPath();
    this.ctx.arc(x, y, glowRadius, 0, Math.PI * 2);
    this.ctx.fill();

    // Draw main circle
    this.ctx.fillStyle = color;
    this.ctx.shadowColor = color;
    this.ctx.shadowBlur = 10 * glowIntensity;
    this.ctx.beginPath();
    this.ctx.arc(x, y, radius, 0, Math.PI * 2);
    this.ctx.fill();

    // Draw bright border
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = 2;
    this.ctx.shadowBlur = 5;
    this.ctx.stroke();

    this.ctx.shadowBlur = 0;
  }

  /**
   * Draw text with neon effect
   */
  drawNeonText(text, x, y, fontSize = 24, color = '#00FFFF') {
    this.ctx.font = `${fontSize}px 'Orbitron', monospace`;
    this.ctx.textAlign = 'center';
    this.ctx.textBaseline = 'middle';

    // Draw glow
    this.ctx.fillStyle = color + '60';
    this.ctx.shadowColor = color;
    this.ctx.shadowBlur = 20;
    this.ctx.fillText(text, x, y);

    // Draw main text
    this.ctx.fillStyle = color;
    this.ctx.shadowBlur = 10;
    this.ctx.fillText(text, x, y);

    // Draw bright inner text
    this.ctx.fillStyle = '#FFFFFF';
    this.ctx.shadowBlur = 0;
    this.ctx.fillText(text, x, y);
  }

  /**
   * Draw particle effect
   */
  drawParticle(particle) {
    const alpha = particle.life / particle.maxLife;
    const size = particle.size * alpha;
    const color = particle.color + Math.floor(alpha * 255).toString(16).padStart(2, '0');

    this.drawNeonCircle(particle.x, particle.y, size, color, alpha);
  }

  /**
   * Draw trail effect for player
   */
  drawTrail(points, color) {
    if (points.length < 2) return;

    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = 3;
    this.ctx.shadowColor = color;
    this.ctx.shadowBlur = 10;

    this.ctx.beginPath();
    this.ctx.moveTo(points[0].x, points[0].y);

    for (let i = 1; i < points.length; i++) {
      const alpha = i / points.length;
      this.ctx.globalAlpha = alpha;
      this.ctx.lineTo(points[i].x, points[i].y);
    }

    this.ctx.stroke();
    this.ctx.globalAlpha = 1;
    this.ctx.shadowBlur = 0;
  }

  /**
   * Draw HUD elements
   */
  drawHUD(gameState) {
    // Score display
    this.drawNeonText(
      `SCORE: ${gameState.score.toLocaleString()}`,
      100, 40, 20, '#00FFFF'
    );

    // Lives display
    this.drawNeonText(
      `LIVES: ${gameState.lives}`,
      100, 70, 16, '#FF1493'
    );

    // Level display
    this.drawNeonText(
      `LEVEL: ${gameState.level}`,
      this.canvas.width - 100, 40, 20, '#00FF00'
    );

    // Power-up status
    if (gameState.powerUpActive) {
      const timeLeft = Math.ceil(gameState.powerUpTimeLeft / 1000);
      this.drawNeonText(
        `POWER-UP: ${timeLeft}s`,
        this.canvas.width - 100, 70, 16, '#FFFF00'
      );
    }
  }

  /**
   * Draw game over screen
   */
  drawGameOver(finalScore, highScore) {
    // Semi-transparent overlay
    this.ctx.fillStyle = 'rgba(0, 0, 0, 0.8)';
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    const centerX = this.canvas.width / 2;
    const centerY = this.canvas.height / 2;

    // Game Over title
    this.drawNeonText('GAME OVER', centerX, centerY - 100, 48, '#FF1493');

    // Final score
    this.drawNeonText(
      `Final Score: ${finalScore.toLocaleString()}`,
      centerX, centerY - 40, 24, '#00FFFF'
    );

    // High score
    if (finalScore > highScore) {
      this.drawNeonText('NEW HIGH SCORE!', centerX, centerY, 20, '#00FF00');
    } else {
      this.drawNeonText(
        `High Score: ${highScore.toLocaleString()}`,
        centerX, centerY, 20, '#FFFF00'
      );
    }

    // Restart instruction
    this.drawNeonText(
      'Press SPACE to restart',
      centerX, centerY + 60, 18, '#FFFFFF'
    );
  }

  /**
   * Draw pause screen
   */
  drawPauseScreen() {
    // Semi-transparent overlay
    this.ctx.fillStyle = 'rgba(0, 0, 0, 0.6)';
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    const centerX = this.canvas.width / 2;
    const centerY = this.canvas.height / 2;

    this.drawNeonText('PAUSED', centerX, centerY, 36, '#FFFF00');
    this.drawNeonText('Press ESC to resume', centerX, centerY + 50, 18, '#FFFFFF');
  }
}

import { GAME_CONSTANTS } from '../utils/Constants.js';
import { CollisionDetector } from '../engine/CollisionDetector.js';

/**
 * Player class for Neon Runner
 * Handles player movement, rendering, and trail effects
 */
export class Player {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.width = GAME_CONSTANTS.PLAYER_SIZE;
    this.height = GAME_CONSTANTS.PLAYER_SIZE;
    this.velocity = { x: 0, y: 0 };
    this.speed = GAME_CONSTANTS.PLAYER_SPEED;
    this.color = GAME_CONSTANTS.PLAYER_COLOR;

    // Trail effect
    this.trail = [];
    this.maxTrailLength = 10;

    // Animation
    this.glowIntensity = 1;
    this.glowDirection = 1;

    // Power-up effects
    this.invulnerable = false;
    this.invulnerableTime = 0;
    this.speedBoost = false;
    this.speedBoostTime = 0;
  }

  /**
   * Update player state
   */
  update(deltaTime, inputManager, canvasWidth, canvasHeight) {
    const deltaSeconds = deltaTime / 1000;

    // Get input movement vector
    const movement = inputManager.getMovementVector();

    // Calculate speed with power-up effects
    let currentSpeed = this.speed;
    if (this.speedBoost) {
      currentSpeed *= 1.5;
      this.speedBoostTime -= deltaTime;
      if (this.speedBoostTime <= 0) {
        this.speedBoost = false;
      }
    }

    // Apply movement with smooth acceleration
    const acceleration = currentSpeed * 3; // Quick acceleration
    this.velocity.x += movement.x * acceleration * deltaSeconds;
    this.velocity.y += movement.y * acceleration * deltaSeconds;

    // Apply friction when not moving
    if (movement.x === 0) {
      this.velocity.x *= GAME_CONSTANTS.FRICTION;
    }
    if (movement.y === 0) {
      this.velocity.y *= GAME_CONSTANTS.FRICTION;
    }

    // Limit maximum velocity
    const maxVel = GAME_CONSTANTS.MAX_VELOCITY;
    if (Math.abs(this.velocity.x) > maxVel) {
      this.velocity.x = Math.sign(this.velocity.x) * maxVel;
    }
    if (Math.abs(this.velocity.y) > maxVel) {
      this.velocity.y = Math.sign(this.velocity.y) * maxVel;
    }

    // Update position
    this.x += this.velocity.x * deltaSeconds;
    this.y += this.velocity.y * deltaSeconds;

    // Keep player within canvas bounds
    this.constrainToCanvas(canvasWidth, canvasHeight);

    // Update trail
    this.updateTrail();

    // Update animations
    this.updateAnimations(deltaTime);

    // Update power-up effects
    this.updatePowerUps(deltaTime);
  }

  /**
   * Keep player within canvas boundaries
   */
  constrainToCanvas(canvasWidth, canvasHeight) {
    if (this.x < 0) {
      this.x = 0;
      this.velocity.x = 0;
    }
    if (this.x + this.width > canvasWidth) {
      this.x = canvasWidth - this.width;
      this.velocity.x = 0;
    }
    if (this.y < 0) {
      this.y = 0;
      this.velocity.y = 0;
    }
    if (this.y + this.height > canvasHeight) {
      this.y = canvasHeight - this.height;
      this.velocity.y = 0;
    }
  }

  /**
   * Update trail effect
   */
  updateTrail() {
    // Add current position to trail
    this.trail.unshift({
      x: this.x + this.width / 2,
      y: this.y + this.height / 2,
      time: Date.now()
    });

    // Remove old trail points
    if (this.trail.length > this.maxTrailLength) {
      this.trail = this.trail.slice(0, this.maxTrailLength);
    }

    // Remove points that are too old
    const now = Date.now();
    this.trail = this.trail.filter(point => now - point.time < 500);
  }

  /**
   * Update animation effects
   */
  updateAnimations(deltaTime) {
    // Pulsing glow effect
    this.glowIntensity += this.glowDirection * (deltaTime / 1000) * 2;
    if (this.glowIntensity > 1.5) {
      this.glowIntensity = 1.5;
      this.glowDirection = -1;
    } else if (this.glowIntensity < 0.7) {
      this.glowIntensity = 0.7;
      this.glowDirection = 1;
    }
  }

  /**
   * Update power-up effects
   */
  updatePowerUps(deltaTime) {
    if (this.invulnerable) {
      this.invulnerableTime -= deltaTime;
      if (this.invulnerableTime <= 0) {
        this.invulnerable = false;
      }
    }
  }

  /**
   * Render player with neon effects
   */
  render(renderer) {
    // Draw trail first
    if (this.trail.length > 1) {
      renderer.drawTrail(this.trail, this.color);
    }

    // Draw player with special effects based on power-ups
    let glowIntensity = this.glowIntensity;
    let color = this.color;

    if (this.invulnerable) {
      // Flashing effect when invulnerable
      const flash = Math.sin(Date.now() / 100) > 0;
      if (flash) {
        color = '#FFFFFF';
        glowIntensity = 2;
      }
    }

    if (this.speedBoost) {
      // Different color when speed boosted
      color = '#FFFF00';
    }

    // Draw main player
    renderer.drawNeonRect(
      this.x, this.y,
      this.width, this.height,
      color, glowIntensity
    );
  }

  /**
   * Check collision with other objects
   */
  checkCollision(object) {
    // Skip collision if invulnerable
    if (this.invulnerable) {
      return false;
    }

    return CollisionDetector.checkRectCollision(this, object);
  }

  /**
   * Handle collision with obstacle
   */
  onObstacleCollision() {
    if (!this.invulnerable) {
      // Become temporarily invulnerable
      this.invulnerable = true;
      this.invulnerableTime = 1000; // 1 second

      // Knockback effect
      this.velocity.x *= -0.5;
      this.velocity.y *= -0.5;

      return true; // Collision occurred
    }
    return false; // No collision due to invulnerability
  }

  /**
   * Handle power-up collection
   */
  collectPowerUp(powerUp) {
    switch (powerUp.type) {
      case 'speed':
        this.speedBoost = true;
        this.speedBoostTime = GAME_CONSTANTS.POWERUP_DURATION;
        break;
      case 'invulnerable':
        this.invulnerable = true;
        this.invulnerableTime = GAME_CONSTANTS.POWERUP_DURATION;
        break;
      case 'shield':
        // Add shield effect (could be implemented later)
        break;
    }
  }

  /**
   * Get player center position
   */
  getCenter() {
    return {
      x: this.x + this.width / 2,
      y: this.y + this.height / 2
    };
  }

  /**
   * Reset player to starting state
   */
  reset(x, y) {
    this.x = x;
    this.y = y;
    this.velocity = { x: 0, y: 0 };
    this.trail = [];
    this.invulnerable = false;
    this.invulnerableTime = 0;
    this.speedBoost = false;
    this.speedBoostTime = 0;
  }
}

import { GAME_CONSTANTS } from '../utils/Constants.js';

/**
 * Obstacle class for Neon Runner
 * Handles obstacle generation, movement, and rendering
 */
export class Obstacle {
  constructor(x, y, width = null, height = null) {
    this.x = x;
    this.y = y;

    // Random size if not specified
    this.width = width || this.getRandomSize();
    this.height = height || this.getRandomSize();

    // Movement properties
    this.velocity = {
      x: -GAME_CONSTANTS.OBSTACLE_SPEED + Math.random() * 100 - 50,
      y: Math.random() * 100 - 50
    };

    // Visual properties
    this.color = GAME_CONSTANTS.OBSTACLE_COLOR;
    this.glowIntensity = 0.8 + Math.random() * 0.4;
    this.rotationSpeed = (Math.random() - 0.5) * 2; // Rotation for visual effect
    this.rotation = 0;

    // State
    this.active = true;
    this.type = this.getRandomType();
  }

  /**
   * Get random obstacle size
   */
  getRandomSize() {
    return GAME_CONSTANTS.OBSTACLE_MIN_SIZE + 
           Math.random() * (GAME_CONSTANTS.OBSTACLE_MAX_SIZE - GAME_CONSTANTS.OBSTACLE_MIN_SIZE);
  }

  /**
   * Get random obstacle type for variety
   */
  getRandomType() {
    const types = ['square', 'rectangle', 'diamond'];
    return types[Math.floor(Math.random() * types.length)];
  }

  /**
   * Update obstacle state
   */
  update(deltaTime, canvasWidth, canvasHeight) {
    const deltaSeconds = deltaTime / 1000;

    // Update position
    this.x += this.velocity.x * deltaSeconds;
    this.y += this.velocity.y * deltaSeconds;

    // Update rotation
    this.rotation += this.rotationSpeed * deltaSeconds;

    // Bounce off top and bottom walls
    if (this.y <= 0 || this.y + this.height >= canvasHeight) {
      this.velocity.y = -this.velocity.y;
      this.y = Math.max(0, Math.min(canvasHeight - this.height, this.y));
    }

    // Mark as inactive if off-screen to the left
    if (this.x + this.width < 0) {
      this.active = false;
    }

    // Update glow intensity for pulsing effect
    this.glowIntensity += Math.sin(Date.now() / 1000 + this.x / 100) * 0.1;
    this.glowIntensity = Math.max(0.5, Math.min(1.2, this.glowIntensity));
  }

  /**
   * Render obstacle with neon effects
   */
  render(renderer) {
    const centerX = this.x + this.width / 2;
    const centerY = this.y + this.height / 2;

    // Save canvas state for rotation
    renderer.ctx.save();
    renderer.ctx.translate(centerX, centerY);
    renderer.ctx.rotate(this.rotation);

    switch (this.type) {
      case 'square':
        this.renderSquare(renderer);
        break;
      case 'rectangle':
        this.renderRectangle(renderer);
        break;
      case 'diamond':
        this.renderDiamond(renderer);
        break;
    }

    // Restore canvas state
    renderer.ctx.restore();
  }

  /**
   * Render square obstacle
   */
  renderSquare(renderer) {
    renderer.drawNeonRect(
      -this.width / 2, -this.height / 2,
      this.width, this.height,
      this.color, this.glowIntensity
    );
  }

  /**
   * Render rectangle obstacle
   */
  renderRectangle(renderer) {
    // Make rectangles wider or taller randomly
    const isWide = this.width > this.height;
    renderer.drawNeonRect(
      -this.width / 2, -this.height / 2,
      this.width, this.height,
      this.color, this.glowIntensity
    );
  }

  /**
   * Render diamond obstacle
   */
  renderDiamond(renderer) {
    const halfWidth = this.width / 2;
    const halfHeight = this.height / 2;

    // Draw diamond shape
    renderer.ctx.fillStyle = this.color;
    renderer.ctx.strokeStyle = this.color;
    renderer.ctx.shadowColor = this.color;
    renderer.ctx.shadowBlur = 15 * this.glowIntensity;
    renderer.ctx.lineWidth = 2;

    renderer.ctx.beginPath();
    renderer.ctx.moveTo(0, -halfHeight);
    renderer.ctx.lineTo(halfWidth, 0);
    renderer.ctx.lineTo(0, halfHeight);
    renderer.ctx.lineTo(-halfWidth, 0);
    renderer.ctx.closePath();

    renderer.ctx.fill();
    renderer.ctx.stroke();

    renderer.ctx.shadowBlur = 0;
  }

  /**
   * Check if obstacle should be removed
   */
  shouldRemove() {
    return !this.active;
  }

  /**
   * Get bounding box for collision detection
   */
  getBounds() {
    return {
      x: this.x,
      y: this.y,
      width: this.width,
      height: this.height
    };
  }
}

/**
 * Obstacle Manager for handling multiple obstacles
 */
export class ObstacleManager {
  constructor(canvasWidth, canvasHeight) {
    this.obstacles = [];
    this.canvasWidth = canvasWidth;
    this.canvasHeight = canvasHeight;
    this.lastSpawnTime = 0;
    this.spawnInterval = GAME_CONSTANTS.OBSTACLE_SPAWN_INTERVAL;
    this.level = 1;
  }

  /**
   * Update all obstacles and spawn new ones
   */
  update(deltaTime, gameTime) {
    // Update existing obstacles
    this.obstacles.forEach(obstacle => {
      obstacle.update(deltaTime, this.canvasWidth, this.canvasHeight);
    });

    // Remove inactive obstacles
    this.obstacles = this.obstacles.filter(obstacle => !obstacle.shouldRemove());

    // Spawn new obstacles
    if (gameTime - this.lastSpawnTime > this.spawnInterval) {
      this.spawnObstacle();
      this.lastSpawnTime = gameTime;
    }

    // Adjust difficulty based on game time
    this.adjustDifficulty(gameTime);
  }

  /**
   * Spawn a new obstacle
   */
  spawnObstacle() {
    const spawnX = this.canvasWidth + 50;
    const spawnY = Math.random() * (this.canvasHeight - 100) + 50;

    // Sometimes spawn multiple obstacles in formation
    if (Math.random() < 0.3) {
      this.spawnFormation(spawnX, spawnY);
    } else {
      this.obstacles.push(new Obstacle(spawnX, spawnY));
    }
  }

  /**
   * Spawn obstacles in formation for variety
   */
  spawnFormation(x, y) {
    const formations = [
      'line', 'triangle', 'wall'
    ];

    const formation = formations[Math.floor(Math.random() * formations.length)];

    switch (formation) {
      case 'line':
        for (let i = 0; i < 3; i++) {
          this.obstacles.push(new Obstacle(x + i * 60, y));
        }
        break;

      case 'triangle':
        this.obstacles.push(new Obstacle(x, y));
        this.obstacles.push(new Obstacle(x + 50, y - 30));
        this.obstacles.push(new Obstacle(x + 50, y + 30));
        break;

      case 'wall':
        const wallHeight = 150;
        const gapSize = 100;
        const gapY = Math.random() * (this.canvasHeight - wallHeight - gapSize) + wallHeight / 2;

        // Top part of wall
        this.obstacles.push(new Obstacle(x, 0, 30, gapY));
        // Bottom part of wall
        this.obstacles.push(new Obstacle(x, gapY + gapSize, 30, this.canvasHeight - gapY - gapSize));
        break;
    }
  }

  /**
   * Adjust difficulty over time
   */
  adjustDifficulty(gameTime) {
    const newLevel = Math.floor(gameTime / 30000) + 1; // Level up every 30 seconds

    if (newLevel !== this.level) {
      this.level = newLevel;

      // Decrease spawn interval (more obstacles)
      this.spawnInterval = Math.max(
        800, 
        GAME_CONSTANTS.OBSTACLE_SPAWN_INTERVAL - (this.level - 1) * 200
      );
    }
  }

  /**
   * Render all obstacles
   */
  render(renderer) {
    this.obstacles.forEach(obstacle => {
      obstacle.render(renderer);
    });
  }

  /**
   * Get all active obstacles
   */
  getObstacles() {
    return this.obstacles;
  }

  /**
   * Clear all obstacles
   */
  clear() {
    this.obstacles = [];
    this.lastSpawnTime = 0;
    this.level = 1;
    this.spawnInterval = GAME_CONSTANTS.OBSTACLE_SPAWN_INTERVAL;
  }

  /**
   * Get current level
   */
  getLevel() {
    return this.level;
  }
}

import { GAME_CONSTANTS } from '../utils/Constants.js';

/**
 * PowerUp class for Neon Runner
 * Handles power-up spawning, movement, collection, and effects
 */
export class PowerUp {
  constructor(x, y, type = null) {
    this.x = x;
    this.y = y;
    this.width = GAME_CONSTANTS.POWERUP_SIZE;
    this.height = GAME_CONSTANTS.POWERUP_SIZE;

    // Power-up type
    this.type = type || this.getRandomType();

    // Movement properties
    this.velocity = {
      x: -GAME_CONSTANTS.POWERUP_SPEED,
      y: Math.sin(Date.now() / 1000) * 50 // Floating motion
    };

    // Visual properties
    this.color = this.getColorForType();
    this.glowIntensity = 1;
    this.rotation = 0;
    this.rotationSpeed = 2;
    this.pulsePhase = Math.random() * Math.PI * 2;

    // State
    this.active = true;
    this.collected = false;
    this.floatOffset = 0;
  }

  /**
   * Get random power-up type
   */
  getRandomType() {
    const types = ['speed', 'invulnerable', 'points', 'life'];
    const weights = [0.3, 0.2, 0.35, 0.15]; // Probability weights

    const random = Math.random();
    let cumulative = 0;

    for (let i = 0; i < types.length; i++) {
      cumulative += weights[i];
      if (random <= cumulative) {
        return types[i];
      }
    }

    return types[0]; // fallback
  }

  /**
   * Get color based on power-up type
   */
  getColorForType() {
    switch (this.type) {
      case 'speed':
        return '#FFFF00'; // Yellow
      case 'invulnerable':
        return '#00FF00'; // Green
      case 'points':
        return '#FF8C00'; // Orange
      case 'life':
        return '#FF69B4'; // Pink
      default:
        return GAME_CONSTANTS.POWERUP_COLOR;
    }
  }

  /**
   * Update power-up state
   */
  update(deltaTime, canvasWidth, canvasHeight) {
    const deltaSeconds = deltaTime / 1000;

    // Update position
    this.x += this.velocity.x * deltaSeconds;

    // Floating motion
    this.floatOffset += deltaSeconds * 3;
    this.y += Math.sin(this.floatOffset) * 30 * deltaSeconds;

    // Keep within vertical bounds
    if (this.y < 0) {
      this.y = 0;
    } else if (this.y + this.height > canvasHeight) {
      this.y = canvasHeight - this.height;
    }

    // Update rotation
    this.rotation += this.rotationSpeed * deltaSeconds;

    // Update glow effect (pulsing)
    this.glowIntensity = 0.8 + 0.4 * Math.sin(Date.now() / 300 + this.pulsePhase);

    // Mark as inactive if off-screen
    if (this.x + this.width < 0) {
      this.active = false;
    }
  }

  /**
   * Render power-up with special effects
   */
  render(renderer) {
    const centerX = this.x + this.width / 2;
    const centerY = this.y + this.height / 2;

    // Save canvas state for rotation
    renderer.ctx.save();
    renderer.ctx.translate(centerX, centerY);
    renderer.ctx.rotate(this.rotation);

    // Draw based on type
    switch (this.type) {
      case 'speed':
        this.renderSpeedPowerUp(renderer);
        break;
      case 'invulnerable':
        this.renderShieldPowerUp(renderer);
        break;
      case 'points':
        this.renderPointsPowerUp(renderer);
        break;
      case 'life':
        this.renderLifePowerUp(renderer);
        break;
      default:
        this.renderDefaultPowerUp(renderer);
        break;
    }

    // Restore canvas state
    renderer.ctx.restore();

    // Draw floating particles around power-up
    this.renderParticles(renderer, centerX, centerY);
  }

  /**
   * Render speed power-up (lightning bolt)
   */
  renderSpeedPowerUp(renderer) {
    const size = this.width / 2;

    // Draw lightning bolt shape
    renderer.ctx.fillStyle = this.color;
    renderer.ctx.strokeStyle = this.color;
    renderer.ctx.shadowColor = this.color;
    renderer.ctx.shadowBlur = 20 * this.glowIntensity;
    renderer.ctx.lineWidth = 3;

    renderer.ctx.beginPath();
    renderer.ctx.moveTo(-size * 0.3, -size);
    renderer.ctx.lineTo(size * 0.3, -size * 0.2);
    renderer.ctx.lineTo(-size * 0.1, -size * 0.2);
    renderer.ctx.lineTo(size * 0.3, size);
    renderer.ctx.lineTo(-size * 0.3, size * 0.2);
    renderer.ctx.lineTo(size * 0.1, size * 0.2);
    renderer.ctx.closePath();

    renderer.ctx.fill();
    renderer.ctx.stroke();

    renderer.ctx.shadowBlur = 0;
  }

  /**
   * Render shield power-up (hexagon)
   */
  renderShieldPowerUp(renderer) {
    const radius = this.width / 2;
    const sides = 6;

    renderer.ctx.fillStyle = this.color;
    renderer.ctx.strokeStyle = this.color;
    renderer.ctx.shadowColor = this.color;
    renderer.ctx.shadowBlur = 15 * this.glowIntensity;
    renderer.ctx.lineWidth = 2;

    renderer.ctx.beginPath();
    for (let i = 0; i < sides; i++) {
      const angle = (i / sides) * Math.PI * 2;
      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius;

      if (i === 0) {
        renderer.ctx.moveTo(x, y);
      } else {
        renderer.ctx.lineTo(x, y);
      }
    }
    renderer.ctx.closePath();

    renderer.ctx.fill();
    renderer.ctx.stroke();

    renderer.ctx.shadowBlur = 0;
  }

  /**
   * Render points power-up (star)
   */
  renderPointsPowerUp(renderer) {
    const outerRadius = this.width / 2;
    const innerRadius = outerRadius * 0.5;
    const spikes = 5;

    renderer.ctx.fillStyle = this.color;
    renderer.ctx.strokeStyle = this.color;
    renderer.ctx.shadowColor = this.color;
    renderer.ctx.shadowBlur = 18 * this.glowIntensity;
    renderer.ctx.lineWidth = 2;

    renderer.ctx.beginPath();
    for (let i = 0; i < spikes * 2; i++) {
      const angle = (i / (spikes * 2)) * Math.PI * 2;
      const radius = i % 2 === 0 ? outerRadius : innerRadius;
      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius;

      if (i === 0) {
        renderer.ctx.moveTo(x, y);
      } else {
        renderer.ctx.lineTo(x, y);
      }
    }
    renderer.ctx.closePath();

    renderer.ctx.fill();
    renderer.ctx.stroke();

    renderer.ctx.shadowBlur = 0;
  }

  /**
   * Render life power-up (heart)
   */
  renderLifePowerUp(renderer) {
    const size = this.width / 2;

    renderer.ctx.fillStyle = this.color;
    renderer.ctx.shadowColor = this.color;
    renderer.ctx.shadowBlur = 15 * this.glowIntensity;

    // Draw heart shape
    renderer.ctx.beginPath();
    renderer.ctx.moveTo(0, -size * 0.3);
    renderer.ctx.bezierCurveTo(-size, -size, -size, size * 0.3, 0, size);
    renderer.ctx.bezierCurveTo(size, size * 0.3, size, -size, 0, -size * 0.3);
    renderer.ctx.closePath();

    renderer.ctx.fill();

    renderer.ctx.shadowBlur = 0;
  }

  /**
   * Render default power-up (diamond)
   */
  renderDefaultPowerUp(renderer) {
    renderer.drawNeonRect(
      -this.width / 2, -this.height / 2,
      this.width, this.height,
      this.color, this.glowIntensity
    );
  }

  /**
   * Render floating particles around power-up
   */
  renderParticles(renderer, centerX, centerY) {
    const particleCount = 8;
    const time = Date.now() / 1000;

    for (let i = 0; i < particleCount; i++) {
      const angle = (i / particleCount) * Math.PI * 2 + time;
      const distance = 30 + Math.sin(time * 2 + i) * 5;
      const x = centerX + Math.cos(angle) * distance;
      const y = centerY + Math.sin(angle) * distance;
      const size = 2 + Math.sin(time * 3 + i) * 1;

      renderer.drawNeonCircle(x, y, size, this.color, 0.5);
    }
  }

  /**
   * Handle collection by player
   */
  collect() {
    if (!this.collected) {
      this.collected = true;
      this.active = false;
      return true;
    }
    return false;
  }

  /**
   * Get effect description for UI
   */
  getEffectDescription() {
    switch (this.type) {
      case 'speed':
        return 'Speed Boost!';
      case 'invulnerable':
        return 'Invulnerability!';
      case 'points':
        return 'Bonus Points!';
      case 'life':
        return 'Extra Life!';
      default:
        return 'Power-Up!';
    }
  }

  /**
   * Get points value
   */
  getPointsValue() {
    switch (this.type) {
      case 'speed':
        return 50;
      case 'invulnerable':
        return 100;
      case 'points':
        return 200;
      case 'life':
        return 500;
      default:
        return GAME_CONSTANTS.SCORE_POWERUP;
    }
  }

  /**
   * Check if power-up should be removed
   */
  shouldRemove() {
    return !this.active;
  }

  /**
   * Get bounding box for collision detection
   */
  getBounds() {
    return {
      x: this.x,
      y: this.y,
      width: this.width,
      height: this.height
    };
  }
}

