/**
 * Game Loop Engine for Neon Runner
 * Handles 60 FPS game loop with requestAnimationFrame
 */
export class GameLoop {
  constructor() {
    this.running = false;
    this.lastTime = 0;
    this.deltaTime = 0;
    this.fps = 0;
    this.frameCount = 0;
    this.lastFpsUpdate = 0;

    // Target FPS
    this.targetFPS = 60;
    this.targetFrameTime = 1000 / this.targetFPS;

    // Callbacks
    this.updateCallback = null;
    this.renderCallback = null;

    // Performance monitoring
    this.performanceStats = {
      averageFPS: 60,
      minFPS: 60,
      maxFPS: 60,
      frameTimeHistory: []
    };

    // Bind the game loop function
    this.gameLoop = this.gameLoop.bind(this);
  }

  /**
   * Set update callback
   */
  setUpdateCallback(callback) {
    this.updateCallback = callback;
  }

  /**
   * Set render callback
   */
  setRenderCallback(callback) {
    this.renderCallback = callback;
  }

  /**
   * Start the game loop
   */
  start() {
    if (!this.running) {
      this.running = true;
      this.lastTime = performance.now();
      this.frameCount = 0;
      this.lastFpsUpdate = this.lastTime;
      requestAnimationFrame(this.gameLoop);
    }
  }

  /**
   * Stop the game loop
   */
  stop() {
    this.running = false;
  }

  /**
   * Main game loop
   */
  gameLoop(currentTime) {
    if (!this.running) return;

    // Calculate delta time
    this.deltaTime = Math.min(currentTime - this.lastTime, 100); // Cap at 100ms
    this.lastTime = currentTime;

    // Update FPS counter
    this.updateFPS(currentTime);

    // Update performance stats
    this.updatePerformanceStats(this.deltaTime);

    // Call update callback
    if (this.updateCallback) {
      this.updateCallback(this.deltaTime, currentTime);
    }

    // Call render callback
    if (this.renderCallback) {
      this.renderCallback(this.deltaTime, currentTime);
    }

    // Continue the loop
    requestAnimationFrame(this.gameLoop);
  }

  /**
   * Update FPS calculation
   */
  updateFPS(currentTime) {
    this.frameCount++;

    if (currentTime - this.lastFpsUpdate >= 1000) {
      this.fps = this.frameCount;
      this.frameCount = 0;
      this.lastFpsUpdate = currentTime;
    }
  }

  /**
   * Update performance statistics
   */
  updatePerformanceStats(deltaTime) {
    const currentFPS = 1000 / deltaTime;

    // Update min/max FPS
    this.performanceStats.minFPS = Math.min(this.performanceStats.minFPS, currentFPS);
    this.performanceStats.maxFPS = Math.max(this.performanceStats.maxFPS, currentFPS);

    // Update frame time history (keep last 60 frames)
    this.performanceStats.frameTimeHistory.push(deltaTime);
    if (this.performanceStats.frameTimeHistory.length > 60) {
      this.performanceStats.frameTimeHistory.shift();
    }

    // Calculate average FPS
    const avgFrameTime = this.performanceStats.frameTimeHistory.reduce((a, b) => a + b, 0) / 
                        this.performanceStats.frameTimeHistory.length;
    this.performanceStats.averageFPS = 1000 / avgFrameTime;
  }

  /**
   * Get current FPS
   */
  getFPS() {
    return this.fps;
  }

  /**
   * Get delta time in milliseconds
   */
  getDeltaTime() {
    return this.deltaTime;
  }

  /**
   * Get performance statistics
   */
  getPerformanceStats() {
    return { ...this.performanceStats };
  }

  /**
   * Check if loop is running
   */
  isRunning() {
    return this.running;
  }

  /**
   * Reset performance statistics
   */
  resetPerformanceStats() {
    this.performanceStats = {
      averageFPS: 60,
      minFPS: 60,
      maxFPS: 60,
      frameTimeHistory: []
    };
  }

  /**
   * Pause the game loop (but keep it active for resume)
   */
  pause() {
    this.running = false;
  }

  /**
   * Resume the game loop
   */
  resume() {
    if (!this.running) {
      this.running = true;
      this.lastTime = performance.now();
      requestAnimationFrame(this.gameLoop);
    }
  }
}

import { GAME_CONSTANTS } from '../utils/Constants.js';
import { Player } from './Player.js';
import { ObstacleManager } from './Obstacle.js';
import { PowerUpManager } from './PowerUp.js';
import { CollisionDetector } from '../engine/CollisionDetector.js';

/**
 * Main Game State Manager for Neon Runner
 * Handles all game logic, state transitions, and coordination
 */
export class Game {
  constructor(renderer, inputManager) {
    this.renderer = renderer;
    this.inputManager = inputManager;

    // Game state
    this.state = GAME_CONSTANTS.STATES.MENU;
    this.score = 0;
    this.lives = 3;
    this.level = 1;
    this.gameTime = 0;
    this.highScore = this.loadHighScore();

    // Game entities
    this.player = new Player(100, 300);
    this.obstacleManager = new ObstacleManager(
      GAME_CONSTANTS.CANVAS_WIDTH, 
      GAME_CONSTANTS.CANVAS_HEIGHT
    );
    this.powerUpManager = new PowerUpManager(
      GAME_CONSTANTS.CANVAS_WIDTH, 
      GAME_CONSTANTS.CANVAS_HEIGHT
    );

    // Power-up effects
    this.powerUpActive = false;
    this.powerUpTimeLeft = 0;
    this.currentPowerUpType = null;

    // Scoring
    this.lastScoreTime = 0;
    this.scoreMultiplier = 1;

    // UI elements
    this.showMessage = false;
    this.messageText = '';
    this.messageTime = 0;
    this.messageColor = '#FFFFFF';

    // Pause functionality
    this.pauseStartTime = 0;
  }

  /**
   * Update game state
   */
  update(deltaTime, currentTime) {
    switch (this.state) {
      case GAME_CONSTANTS.STATES.MENU:
        this.updateMenu(deltaTime);
        break;
      case GAME_CONSTANTS.STATES.PLAYING:
        this.updatePlaying(deltaTime, currentTime);
        break;
      case GAME_CONSTANTS.STATES.PAUSED:
        this.updatePaused(deltaTime);
        break;
      case GAME_CONSTANTS.STATES.GAME_OVER:
        this.updateGameOver(deltaTime);
        break;
    }
  }

  /**
   * Update menu state
   */
  updateMenu(deltaTime) {
    // Check for start game input
    if (this.inputManager.wasKeyPressed('Space')) {
      this.startGame();
    }
  }

  /**
   * Update playing state
   */
  updatePlaying(deltaTime, currentTime) {
    // Check for pause input
    if (this.inputManager.wasKeyPressed('Escape')) {
      this.pauseGame();
      return;
    }

    // Update game time
    this.gameTime += deltaTime;

    // Update player
    this.player.update(
      deltaTime, 
      this.inputManager, 
      GAME_CONSTANTS.CANVAS_WIDTH, 
      GAME_CONSTANTS.CANVAS_HEIGHT
    );

    // Update obstacles
    this.obstacleManager.update(deltaTime, this.gameTime);

    // Update power-ups
    this.powerUpManager.update(deltaTime, this.gameTime);

    // Update power-up effects
    this.updatePowerUpEffects(deltaTime);

    // Check collisions
    this.checkCollisions();

    // Update score
    this.updateScore(deltaTime);

    // Update level
    this.updateLevel();

    // Update messages
    this.updateMessages(deltaTime);
  }

  /**
   * Update paused state
   */
  updatePaused(deltaTime) {
    // Check for resume input
    if (this.inputManager.wasKeyPressed('Escape')) {
      this.resumeGame();
    }
  }

  /**
   * Update game over state
   */
  updateGameOver(deltaTime) {
    // Check for restart input
    if (this.inputManager.wasKeyPressed('Space')) {
      this.startGame();
    }
  }

  /**
   * Update power-up effects
   */
  updatePowerUpEffects(deltaTime) {
    if (this.powerUpActive) {
      this.powerUpTimeLeft -= deltaTime;

      if (this.powerUpTimeLeft <= 0) {
        this.powerUpActive = false;
        this.currentPowerUpType = null;
        this.scoreMultiplier = 1;
      }
    }
  }

  /**
   * Check all collisions
   */
  checkCollisions() {
    // Player vs Obstacles
    const obstacles = this.obstacleManager.getObstacles();
    for (const obstacle of obstacles) {
      if (this.player.checkCollision(obstacle)) {
        if (this.player.onObstacleCollision()) {
          this.handlePlayerHit();
          break;
        }
      }
    }

    // Player vs Power-ups
    const powerUps = this.powerUpManager.getPowerUps();
    for (const powerUp of powerUps) {
      if (CollisionDetector.checkRectCollision(this.player, powerUp)) {
        this.collectPowerUp(powerUp);
        break;
      }
    }
  }

  /**
   * Handle player hit by obstacle
   */
  handlePlayerHit() {
    this.lives--;
    this.showMessage('Hit!', '#FF1493', 1000);

    if (this.lives <= 0) {
      this.gameOver();
    }
  }

  /**
   * Handle power-up collection
   */
  collectPowerUp(powerUp) {
    if (powerUp.collect()) {
      // Apply power-up effect
      this.applyPowerUpEffect(powerUp);

      // Add score
      this.addScore(powerUp.getPointsValue());

      // Show message
      this.showMessage(
        powerUp.getEffectDescription(),
        powerUp.color,
        2000
      );
    }
  }

  /**
   * Apply power-up effect
   */
  applyPowerUpEffect(powerUp) {
    switch (powerUp.type) {
      case 'speed':
        this.player.collectPowerUp(powerUp);
        this.powerUpActive = true;
        this.powerUpTimeLeft = GAME_CONSTANTS.POWERUP_DURATION;
        this.currentPowerUpType = 'speed';
        break;

      case 'invulnerable':
        this.player.collectPowerUp(powerUp);
        this.powerUpActive = true;
        this.powerUpTimeLeft = GAME_CONSTANTS.POWERUP_DURATION;
        this.currentPowerUpType = 'invulnerable';
        break;

      case 'points':
        this.scoreMultiplier = 2;
        this.powerUpActive = true;
        this.powerUpTimeLeft = GAME_CONSTANTS.POWERUP_DURATION;
        this.currentPowerUpType = 'points';
        break;

      case 'life':
        this.lives++;
        break;
    }
  }

  /**
   * Update score
   */
  updateScore(deltaTime) {
    // Base score over time
    const timeBonus = Math.floor((deltaTime / 1000) * GAME_CONSTANTS.SCORE_PER_SECOND * this.scoreMultiplier);
    this.addScore(timeBonus);
  }

  /**
   * Add score with validation
   */
  addScore(points) {
    this.score += Math.max(0, points);

    // Update high score
    if (this.score > this.highScore) {
      this.highScore = this.score;
      this.saveHighScore();
    }
  }

  /**
   * Update level based on score/time
   */
  updateLevel() {
    const newLevel = Math.floor(this.gameTime / 30000) + 1;
    if (newLevel !== this.level) {
      this.level = newLevel;
      this.showMessage(`Level ${this.level}!`, '#00FFFF', 2000);
    }
  }

  /**
   * Update UI messages
   */
  updateMessages(deltaTime) {
    if (this.showMessage) {
      this.messageTime -= deltaTime;
      if (this.messageTime <= 0) {
        this.showMessage = false;
      }
    }
  }

  /**
   * Show a temporary message
   */
  showMessage(text, color = '#FFFFFF', duration = 1000) {
    this.messageText = text;
    this.messageColor = color;
    this.messageTime = duration;
    this.showMessage = true;
  }

  /**
   * Start new game
   */
  startGame() {
    this.state = GAME_CONSTANTS.STATES.PLAYING;
    this.score = 0;
    this.lives = 3;
    this.level = 1;
    this.gameTime = 0;
    this.scoreMultiplier = 1;

    // Reset entities
    this.player.reset(100, 300);
    this.obstacleManager.clear();
    this.powerUpManager.clear();

    // Reset power-ups
    this.powerUpActive = false;
    this.powerUpTimeLeft = 0;
    this.currentPowerUpType = null;

    // Clear messages
    this.showMessage = false;
  }

  /**
   * Pause game
   */
  pauseGame() {
    if (this.state === GAME_CONSTANTS.STATES.PLAYING) {
      this.state = GAME_CONSTANTS.STATES.PAUSED;
      this.pauseStartTime = performance.now();
    }
  }

  /**
   * Resume game
   */
  resumeGame() {
    if (this.state === GAME_CONSTANTS.STATES.PAUSED) {
      this.state = GAME_CONSTANTS.STATES.PLAYING;
    }
  }

  /**
   * Game over
   */
  gameOver() {
    this.state = GAME_CONSTANTS.STATES.GAME_OVER;
    this.saveHighScore();
  }

  /**
   * Render game
   */
  render() {
    // Clear canvas
    this.renderer.clear();

    switch (this.state) {
      case GAME_CONSTANTS.STATES.MENU:
        this.renderMenu();
        break;
      case GAME_CONSTANTS.STATES.PLAYING:
        this.renderPlaying();
        break;
      case GAME_CONSTANTS.STATES.PAUSED:
        this.renderPlaying();
        this.renderer.drawPauseScreen();
        break;
      case GAME_CONSTANTS.STATES.GAME_OVER:
        this.renderPlaying();
        this.renderer.drawGameOver(this.score, this.highScore);
        break;
    }
  }

  /**
   * Render menu screen
   */
  renderMenu() {
    const centerX = GAME_CONSTANTS.CANVAS_WIDTH / 2;
    const centerY = GAME_CONSTANTS.CANVAS_HEIGHT / 2;

    // Title
    this.renderer.drawNeonText('NEON RUNNER', centerX, centerY - 100, 48, '#00FFFF');

    // Instructions
    this.renderer.drawNeonText('Use arrow keys to move', centerX, centerY - 20, 20, '#FFFFFF');
    this.renderer.drawNeonText('Avoid obstacles, collect power-ups', centerX, centerY + 10, 20, '#FFFFFF');

    // High score
    this.renderer.drawNeonText(
      `High Score: ${this.highScore.toLocaleString()}`,
      centerX, centerY + 50, 18, '#FFFF00'
    );

    // Start instruction
    this.renderer.drawNeonText('Press SPACE to start', centerX, centerY + 100, 24, '#00FF00');
  }

  /**
   * Render playing state
   */
  renderPlaying() {
    // Render game entities
    this.obstacleManager.render(this.renderer);
    this.powerUpManager.render(this.renderer);
    this.player.render(this.renderer);

    // Render HUD
    this.renderer.drawHUD({
      score: this.score,
      lives: this.lives,
      level: this.level,
      powerUpActive: this.powerUpActive,
      powerUpTimeLeft: this.powerUpTimeLeft
    });

    // Render message if active
    if (this.showMessage) {
      this.renderer.drawNeonText(
        this.messageText,
        GAME_CONSTANTS.CANVAS_WIDTH / 2,
        GAME_CONSTANTS.CANVAS_HEIGHT / 2,
        24,
        this.messageColor
      );
    }
  }

  /**
   * Get current game state
   */
  getState() {
    return {
      state: this.state,
      score: this.score,
      lives: this.lives,
      level: this.level,
      gameTime: this.gameTime,
      highScore: this.highScore,
      powerUpActive: this.powerUpActive,
      powerUpTimeLeft: this.powerUpTimeLeft
    };
  }

  /**
   * Load high score from localStorage
   */
  loadHighScore() {
    try {
      const saved = localStorage.getItem('neonRunnerHighScore');
      return saved ? parseInt(saved) : 0;
    } catch (e) {
      return 0;
    }
  }

  /**
   * Save high score to localStorage
   */
  saveHighScore() {
    try {
      localStorage.setItem('neonRunnerHighScore', this.highScore.toString());
    } catch (e) {
      console.warn('Could not save high score to localStorage');
    }
  }
}

/**
 * Neon Runner - Main Entry Point
 * Cyberpunk-themed endless runner game
 * 
 * Controls: Arrow keys to move, Space to start/restart, Escape to pause
 */

import { GAME_CONSTANTS, INPUT_KEYS } from './js/utils/Constants.js';
import { GameLoop } from './js/engine/GameLoop.js';
import { InputManager } from './js/engine/InputManager.js';
import { Renderer } from './js/engine/Renderer.js';
import { Game } from './js/game/Game.js';

/**
 * Main application class
 */
class NeonRunnerApp {
  constructor() {
    // Get canvas and context
    this.canvas = document.getElementById('game-canvas');
    if (!this.canvas) {
      throw new Error('Canvas element not found!');
    }

    this.ctx = this.canvas.getContext('2d');
    if (!this.ctx) {
      throw new Error('Could not get canvas 2D context!');
    }

    // Initialize engine components
    this.gameLoop = new GameLoop();
    this.inputManager = new InputManager();
    this.renderer = new Renderer(this.canvas, this.ctx);

    // Initialize game
    this.game = new Game(this.renderer, this.inputManager);

    // Debug mode (show FPS and performance stats)
    this.debugMode = false;

    // Setup event listeners
    this.setupEventListeners();

    // Loading state
    this.isLoaded = false;
  }

  /**
   * Initialize the application
   */
  async init() {
    try {
      console.log('🎮 Initializing Neon Runner...');

      // Setup canvas
      this.setupCanvas();

      // Setup game loop callbacks
      this.gameLoop.setUpdateCallback((deltaTime, currentTime) => {
        this.update(deltaTime, currentTime);
      });

      this.gameLoop.setRenderCallback((deltaTime, currentTime) => {
        this.render(deltaTime, currentTime);
      });

      // Show loading screen
      this.renderLoadingScreen();

      // Preload assets (if any)
      await this.preloadAssets();

      // Start the game loop
      this.gameLoop.start();
      this.isLoaded = true;

      console.log('✅ Neon Runner initialized successfully!');
      console.log('🎯 Controls: Arrow keys to move, Space to start, Escape to pause');

    } catch (error) {
      console.error('❌ Failed to initialize game:', error);
      this.handleInitError(error);
    }
  }

  /**
   * Setup canvas properties
   */
  setupCanvas() {
    // Set canvas size
    this.canvas.width = GAME_CONSTANTS.CANVAS_WIDTH;
    this.canvas.height = GAME_CONSTANTS.CANVAS_HEIGHT;

    // Set CSS size for responsive design
    this.canvas.style.width = '100%';
    this.canvas.style.height = '100%';
    this.canvas.style.maxWidth = `${GAME_CONSTANTS.CANVAS_WIDTH}px`;
    this.canvas.style.maxHeight = `${GAME_CONSTANTS.CANVAS_HEIGHT}px`;

    // Enable image smoothing
    this.ctx.imageSmoothingEnabled = true;
    this.ctx.imageSmoothingQuality = 'high';

    console.log(`📺 Canvas setup: ${this.canvas.width}x${this.canvas.height}`);
  }

  /**
   * Setup additional event listeners
   */
  setupEventListeners() {
    // Handle window resize
    window.addEventListener('resize', () => {
      this.handleResize();
    });

    // Handle window focus/blur for pause functionality
    window.addEventListener('blur', () => {
      if (this.game.state === GAME_CONSTANTS.STATES.PLAYING) {
        this.game.pauseGame();
      }
    });

    // Handle visibility change (tab switching)
    document.addEventListener('visibilitychange', () => {
      if (document.hidden && this.game.state === GAME_CONSTANTS.STATES.PLAYING) {
        this.game.pauseGame();
      }
    });

    // Debug mode toggle (press D key)
    document.addEventListener('keydown', (e) => {
      if (e.code === 'KeyD' && e.ctrlKey) {
        e.preventDefault();
        this.debugMode = !this.debugMode;
        console.log(`🔧 Debug mode: ${this.debugMode ? 'ON' : 'OFF'}`);
      }
    });

    // Handle fullscreen toggle (press F key)
    document.addEventListener('keydown', (e) => {
      if (e.code === 'KeyF' && e.altKey) {
        e.preventDefault();
        this.toggleFullscreen();
      }
    });
  }

  /**
   * Handle window resize
   */
  handleResize() {
    // The CSS handles responsive sizing, but we can add logic here if needed
    console.log('🔄 Window resized');
  }

  /**
   * Toggle fullscreen mode
   */
  toggleFullscreen() {
    if (!document.fullscreenElement) {
      this.canvas.requestFullscreen().catch(err => {
        console.warn('Could not enter fullscreen:', err);
      });
    } else {
      document.exitFullscreen();
    }
  }

  /**
   * Preload game assets
   */
  async preloadAssets() {
    // For now, we don't have external assets to load
    // This is where you would load images, sounds, etc.
    return new Promise(resolve => {
      setTimeout(resolve, 500); // Simulate loading time
    });
  }

  /**
   * Main update loop
   */
  update(deltaTime, currentTime) {
    if (!this.isLoaded) return;

    // Update input manager
    this.inputManager.update();

    // Update game
    this.game.update(deltaTime, currentTime);
  }

  /**
   * Main render loop
   */
  render(deltaTime, currentTime) {
    if (!this.isLoaded) {
      this.renderLoadingScreen();
      return;
    }

    // Render game
    this.game.render();

    // Render debug information
    if (this.debugMode) {
      this.renderDebugInfo();
    }
  }

  /**
   * Render loading screen
   */
  renderLoadingScreen() {
    this.renderer.clear();

    const centerX = GAME_CONSTANTS.CANVAS_WIDTH / 2;
    const centerY = GAME_CONSTANTS.CANVAS_HEIGHT / 2;

    this.renderer.drawNeonText('LOADING...', centerX, centerY, 36, '#00FFFF');

    // Animated loading dots
    const dots = Math.floor(Date.now() / 500) % 4;
    this.renderer.drawNeonText('.'.repeat(dots), centerX, centerY + 50, 24, '#FFFFFF');
  }

  /**
   * Render debug information
   */
  renderDebugInfo() {
    const stats = this.gameLoop.getPerformanceStats();
    const gameState = this.game.getState();

    // Debug panel background
    this.ctx.fillStyle = 'rgba(0, 0, 0, 0.8)';
    this.ctx.fillRect(10, 10, 200, 120);

    // Debug text
    this.ctx.fillStyle = '#00FFFF';
    this.ctx.font = '12px monospace';
    this.ctx.textAlign = 'left';

    let y = 25;
    const lineHeight = 15;

    this.ctx.fillText(`FPS: ${this.gameLoop.getFPS()}`, 15, y);
    y += lineHeight;
    this.ctx.fillText(`Avg FPS: ${stats.averageFPS.toFixed(1)}`, 15, y);
    y += lineHeight;
    this.ctx.fillText(`Delta: ${this.gameLoop.getDeltaTime().toFixed(1)}ms`, 15, y);
    y += lineHeight;
    this.ctx.fillText(`State: ${gameState.state}`, 15, y);
    y += lineHeight;
    this.ctx.fillText(`Score: ${gameState.score}`, 15, y);
    y += lineHeight;
    this.ctx.fillText(`Level: ${gameState.level}`, 15, y);
    y += lineHeight;
    this.ctx.fillText(`Lives: ${gameState.lives}`, 15, y);

    // Reset text alignment
    this.ctx.textAlign = 'center';
  }

  /**
   * Handle initialization errors
   */
  handleInitError(error) {
    // Show error on canvas if possible
    if (this.ctx) {
      this.ctx.fillStyle = '#FF0000';
      this.ctx.font = '24px Arial';
      this.ctx.textAlign = 'center';
      this.ctx.fillText('Failed to load game', 
        GAME_CONSTANTS.CANVAS_WIDTH / 2, 
        GAME_CONSTANTS.CANVAS_HEIGHT / 2);
      this.ctx.fillText(error.message, 
        GAME_CONSTANTS.CANVAS_WIDTH / 2, 
        GAME_CONSTANTS.CANVAS_HEIGHT / 2 + 30);
    }

    // Also show in DOM
    const errorDiv = document.createElement('div');
    errorDiv.style.cssText = `
      position: fixed;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      background: #ff0000;
      color: white;
      padding: 20px;
      border-radius: 10px;
      font-family: Arial, sans-serif;
      z-index: 1000;
    `;
    errorDiv.innerHTML = `
      <h3>Game Loading Error</h3>
      <p>${error.message}</p>
      <p>Please refresh the page and try again.</p>
    `;
    document.body.appendChild(errorDiv);
  }

  /**
   * Cleanup resources
   */
  destroy() {
    this.gameLoop.stop();
    console.log('🧹 Neon Runner destroyed');
  }
}

/**
 * Initialize the game when DOM is ready
 */
function initializeGame() {
  console.log('🚀 Starting Neon Runner initialization...');

  try {
    const app = new NeonRunnerApp();
    app.init();

    // Store app instance globally for debugging
    window.neonRunner = app;

  } catch (error) {
    console.error('💥 Critical error during initialization:', error);
  }
}

// Start the game
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initializeGame);
} else {
  initializeGame();
}

// Handle page unload
window.addEventListener('beforeunload', () => {
  if (window.neonRunner) {
    window.neonRunner.destroy();
  }
});

